def dot(a, b):
    return sum(x * y for x, y in zip(a, b))

inputs  = [1.0, 2.0, 3.0]
weights = [0.5, 0.5, 0.5]

result = dot(inputs, weights)
print(f'Dot product: {result}')  # 3.0

def relu(x):
    return max(0, x)

test_values = [-5, -1, 0, 2, 7]
for v in test_values:
    print(f'ReLU({v:3d}) = {relu(v)}')

import math

def sigmoid(x):
    return 1 / (1 + math.exp(-x))

for x in [-5, 0, 5]:
    print(f'sigmoid({x:3d}) = {sigmoid(x):.4f}')
